export default function hoverConfig(e) {

let idElement = e.target.id

    if(e.type === 'mouseenter'){

        setTimeout(() => {
            console.log(idElement)
            console.log(e.target.id)
            if(idElement === e.target.id) console.log('disparou');
        }, 2000)

    }else if(e.type === 'mouseleave'){
        
        idElement = null;

    }


}
